import {toGrayscale,grayToImageData} from './grayscale.js';import {applyToneAdjustments} from './toneAdjust.js';import {posterize} from './posterize.js';import {createFigureMask} from './mask.js';import {generateCumulativeHatching} from './cumulativeLayers.js';import {generateInternalEdges} from './edges.js';import {generateDetailEdges} from './details.js';import {traceOuterBorder} from './outerBorder.js';
export function buildPreviewData(imageData,config){const base=toGrayscale(imageData);const adjusted=applyToneAdjustments(base,config.tone);const mask=createFigureMask(adjusted,config.mask);const levelMap=posterize(adjusted,config.posterize);for(let i=0;i<levelMap.map.length;i++)if(!mask[i])levelMap.map[i]=0;return {base,adjusted,mask,levelMap,adjustedImageData:grayToImageData(adjusted.gray,adjusted.width,adjusted.height),posterImageData:grayToImageData(levelMap.map,levelMap.width,levelMap.height,levelMap.levels)}}
export function generateDocument(imageData,config){const t=performance.now();const p=buildPreviewData(imageData,config);const layers=[traceOuterBorder(p.mask,p.levelMap.width,p.levelMap.height,config.border),generateInternalEdges(p.levelMap,p.mask,config.edges),generateDetailEdges(p.adjusted,p.mask,config.details),...generateCumulativeHatching(p.levelMap,p.mask,config)];const segments=layers.filter(Boolean).reduce((n,l)=>n+(l.segments?.length||0),0);return {...p,layers:layers.filter(Boolean),model:{width:p.levelMap.width,height:p.levelMap.height,layers:layers.filter(Boolean)},stats:{segments,layers:layers.filter(Boolean).length,ms:performance.now()-t,warnings:segments>config.hatching.maxSegmentsWarning?[`High segment count: ${segments}`]:[]}}}
